  1	import {
  2	  K8sResourceKind,
  3	  PrometheusEndpoint,
  4	  PrometheusResponse,
  5	  usePrometheusPoll
  6	} from '@openshift-console/dynamic-plugin-sdk';
  7	import { Flex, FlexItem, Slider, Spinner, Text, TextVariants } from '@patternfly/react-core';
  8	import { InfoAltIcon, WarningTriangleIcon } from '@patternfly/react-icons';
  9	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 10	import _ from 'lodash';
 11	import React, { FC } from 'react';
 12	import { useTranslation } from 'react-i18next';
 13	import './forms.css';
 14	
 15	export type ResourceCalculatorProps = {
 16	  flowCollector: K8sResourceKind | null;
 17	  setSampling: (sampling: number) => void;
 18	};
 19	
 20	export const Consumption: FC<ResourceCalculatorProps> = ({ flowCollector, setSampling }) => {
 21	  const { t } = useTranslation('plugin__netobserv-plugin');
 22	
 23	  const [receivedPackets, rpLoaded, rpError] = usePrometheusPoll({
 24	    endpoint: PrometheusEndpoint.QUERY,
 25	    query: `sort_desc(sum(irate(container_network_receive_packets_total{cluster="",namespace=~".+"}[4h])) by (node,namespace,pod))`
 26	  });
 27	
 28	  const [transmittedPackets, tpLoaded, tpError] = usePrometheusPoll({
 29	    endpoint: PrometheusEndpoint.QUERY,
 30	    query: `sort_desc(sum(irate(container_network_transmit_packets_total{cluster="",namespace=~".+"}[4h])) by (node,namespace,pod))`
 31	  });
 32	
 33	  const getCurrentSampling = React.useCallback(() => {
 34	    return (flowCollector?.spec?.agent?.ebpf?.sampling as number) || 50;
 35	  }, [flowCollector?.spec?.agent?.ebpf?.sampling]);
 36	
 37	  const getSamplings = React.useCallback(() => {
 38	    const current = getCurrentSampling();
 39	    let samplings = [1, 25, 50, 100, 500, 1000];
 40	    if (!samplings.includes(current)) {
 41	      samplings.push(current);
 42	      samplings = _.sortBy(samplings);
 43	    }
 44	    return samplings;
 45	  }, [getCurrentSampling]);
 46	
 47	  const getSamplingIndex = React.useCallback(() => {
 48	    const current = getCurrentSampling();
 49	    const idx = getSamplings().indexOf(current);
 50	    if (idx < 0) {
 51	      return 0;
 52	    }
 53	    return idx;
 54	  }, [getSamplings, getCurrentSampling]);
 55	
 56	  const loadingComponent = () => <Spinner size="lg" />;
 57	
 58	  const errorComponent = () => <WarningTriangleIcon />;
 59	
 60	  const value = (response?: PrometheusResponse) => {
 61	    if (!response) {
 62	      return 0;
 63	    }
 64	    return _.sumBy(response.data.result, r => Number(r.value![1]));
 65	  };
 66	
 67	  const labelsCount = React.useCallback(
 68	    (label: string) => {
 69	      if (!rpLoaded) {
 70	        return loadingComponent();
 71	      } else if (rpError) {
 72	        return errorComponent();
 73	      } else if (!receivedPackets) {
 74	        return t('n/a');
 75	      }
 76	      return _.uniq(_.map(receivedPackets.data.result, r => r.metric[label])).length;
 77	    },
 78	    // eslint-disable-next-line react-hooks/exhaustive-deps
 79	    [receivedPackets, rpError, rpLoaded]
 80	  );
 81	
 82	  const getEstimation = React.useCallback(
 83	    (sampling: number) => {
 84	      // eslint-disable-next-line max-len
 85	      // taken from https://docs.redhat.com/en/documentation/openshift_container_platform/4.18/html/network_observability/configuring-network-observability-operators#network-observability-total-resource-usage-table_network_observability
 86	
 87	      // TODO: rely on more than nodes here
 88	      const nodesResult = labelsCount('node');
 89	      const nodes = typeof nodesResult === 'number' ? nodesResult : 0;
 90	      const estimatedCPU = nodes <= 25 ? -0.0096 * sampling + 1.8296 : -0.1347 * sampling + 12.1247;
 91	      const estimatedMemory = nodes <= 25 ? -0.1224 * sampling + 22.1224 : -0.4898 * sampling + 87.4898;
 92	      return {
 93	        cpu: estimatedCPU > 0 ? estimatedCPU.toFixed(2) : '< 0.1',
 94	        memory: estimatedMemory > 0 ? estimatedMemory.toFixed(0) : '< 1'
 95	      };
 96	    },
 97	    [labelsCount]
 98	  );
 99	
100	  const getRecommendations = React.useCallback(() => {
101	    // eslint-disable-next-line max-len
102	    // taken from https://docs.redhat.com/en/documentation/openshift_container_platform/4.18/html/network_observability/configuring-network-observability-operators
103	    const nodesResult = labelsCount('node');
104	    const nodes = typeof nodesResult === 'number' ? nodesResult : 0;
105	    return [
106	      {
107	        cpu: nodes <= 10 ? 4 : 16,
108	        memory: nodes <= 10 ? 16 : 64,
109	        lokistackSize: nodes <= 10 ? '1x.extra-small' : nodes <= 25 ? '1x.small' : '1x.medium',
110	        kafka: nodes <= 25 ? '6 consumers' : '18 consumers'
111	      }
112	    ];
113	  }, [labelsCount]);
114	
115	  return (
116	    <Flex direction={{ default: 'column' }}>
117	      <FlexItem className="calculator-item">
118	        <Text component={TextVariants.h2}>{t('Cluster metrics')}</Text>
119	        <Table variant={TableVariant.compact}>
120	          <Thead>
121	            <Tr>
122	              <Th>{t('Bandwidth')}</Th>
123	              <Th>{t('Nodes')}</Th>
124	              <Th>{t('Namespaces')}</Th>
125	              <Th>{t('Pods')}</Th>
126	            </Tr>
127	          </Thead>
128	          <Tbody>
129	            <Tr>
130	              <Td>
131	                {!rpLoaded || !tpLoaded
132	                  ? loadingComponent()
133	                  : rpError || tpError
134	                  ? errorComponent()
135	                  : `${Math.round(value(receivedPackets) + value(transmittedPackets))} pps`}
136	              </Td>
137	              <Td>{labelsCount('node')}</Td>
138	              <Td>{labelsCount('namespace')}</Td>
139	              <Td>{labelsCount('pod')}</Td>
140	            </Tr>
141	          </Tbody>
142	        </Table>
143	      </FlexItem>
144	      <FlexItem className="calculator-item">
145	        <Text component={TextVariants.h2}>{t('Recommendations')}</Text>
146	        <span className="co-pre-line">
147	          {t(
148	            // eslint-disable-next-line max-len
149	            'The example outlined in the table demonstrates a scenario that is tailored to your workload. Consider this example only as a baseline from which adjustments can be made to accommodate your needs.'
150	          )}
151	        </span>
152	        <Table variant={TableVariant.compact}>
153	          <Thead>
154	            <Tr>
155	              <Th>{t('vCPU')}</Th>
156	              <Th>{t('Memory')}</Th>
157	              <Th>{t('LokiStack size')}</Th>
158	              <Th>{t('Kafka')}</Th>
159	            </Tr>
160	          </Thead>
161	          <Tbody>
162	            {getRecommendations().map((reco, i) => {
163	              return (
164	                <Tr key={i}>
165	                  <Td>{`${reco.cpu}vCPUs`}</Td>
166	                  <Td>{`${reco.memory}GiB`}</Td>
167	                  <Td>{reco.lokistackSize}</Td>
168	                  <Td>{reco.kafka}</Td>
169	                </Tr>
170	              );
171	            })}
172	          </Tbody>
173	        </Table>
174	      </FlexItem>
175	      <FlexItem>
176	        <Text component={TextVariants.h2}>{t('Performance tuning and estimation')}</Text>
177	        <span className="co-pre-line">
178	          {t(
179	            // eslint-disable-next-line max-len
180	            'The sampling interval is one of the main settings used to balance performance and accuracy. The lower the interval, the higher the accuracy.'
181	          )}
182	          <br />
183	          {t('Use the slider below to configure the desired sampling interval.')}
184	        </span>
185	        <Slider
186	          value={getSamplingIndex()}
187	          customSteps={getSamplings().map((s, i) => ({ value: i, label: String(s) }))}
188	          max={getSamplings().length - 1}
189	          onChange={(_, value) => {
190	            setSampling(getSamplings()[value]);
191	          }}
192	        />
193	        <Table id={'estimation-table'} variant={TableVariant.compact}>
194	          <Thead>
195	            <Tr>
196	              <Th>{t('Sampling interval')}</Th>
197	              <Th>{t('vCPU')}</Th>
198	              <Th>{t('Memory')}</Th>
199	            </Tr>
200	          </Thead>
201	          <Tbody>
202	            {getSamplings().map((sampling, i) => {
203	              const current = getCurrentSampling() === sampling;
204	              const estimate = getEstimation(sampling);
205	              return (
206	                <Tr
207	                  key={i}
208	                  isSelectable={setSampling !== undefined}
209	                  isClickable={setSampling !== undefined}
210	                  isRowSelected={current}
211	                  onClick={() => setSampling && setSampling(sampling)}
212	                >
213	                  <Td>{sampling}</Td>
214	                  <Td>{`${estimate.cpu}vCPUs`}</Td>
215	                  <Td>{`${estimate.memory}GiB`}</Td>
216	                </Tr>
217	              );
218	            })}
219	          </Tbody>
220	        </Table>
221	        <span>
222	          <InfoAltIcon />{' '}
223	          {t(
224	            // eslint-disable-next-line max-len
225	            'The estimations are based on the number of nodes in the cluster and the sampling rate. They do not take into account the number of namespaces or pods, as their impact is comparatively lower than that of nodes.\nThey are calculated using a linear regression model based on data collected from various OpenShift clusters. Actual resource consumption may vary depending on your specific workload and cluster configuration.'
226	          )}
227	        </span>
228	      </FlexItem>
229	    </Flex>
230	  );
231	};
232	
233	export default Consumption;

